return ['domain'=>NULL,'plural-forms'=>'nplurals=3; plural=((n==1) ? 0 : (n>=2 && n<=4) ? 1 : 2);','language'=>'cs_CZ','project-id-version'=>'TranslatePress Multilingual','pot-creation-date'=>'2026-05-25T19:29:27+03:00','po-revision-date'=>'2026-05-25T19:29:27+03:00','x-generator'=>'TranslatePress build (community + OpenRouter), 2026-05-25','messages'=>['Please update the TranslatePress - Multilingual plugin to version %1$s or higher to ensure %2$s functions correctly.'=>'Aktualizujte prosím plugin TranslatePress - Multilingual na verzi %1$s nebo vyšší, aby %2$s správně fungoval.','Please install and activate the TranslatePress - Multilingual plugin'=>'Nainstalujte a aktivujte prosím plugin TranslatePress - Multilingual','Install & Activate'=>'Nainstalovat & aktivovat','Please update TranslatePress - Multilingual to version %2$s or newer. Your currently installed version of TranslatePress - Multilingual is no longer compatible with the current version of %1$s.'=>'Aktualizujte prosím TranslatePress - Multilingual na verzi %2$s nebo novější. Vaše aktuálně nainstalovaná verze TranslatePress - Multilingual již není kompatibilní s aktuální verzí %1$s.','All TranslatePress functionalities are disabled until then.'=>'Do té doby jsou všechny funkce TranslatePress deaktivovány.','Update Now'=>'Aktualizovat nyní','This TranslatePress add-on has been migrated to the main plugin and is no longer used. You can delete it.'=>'Tento doplněk TranslatePress byl přesunut do hlavního pluginu a již se nepoužívá. Můžete jej smazat.','<strong>TranslatePress</strong> requires at least PHP version 5.6.20+ to run. It is the <a href="%s">minimum requirement of the latest WordPress version</a>. Please contact your server administrator to update your PHP version.'=>'<strong>TranslatePress</strong> ke spuštění vyžaduje alespoň PHP verzi 5.6.20+. Jedná se o <a href="%s">minimální požadavek nejnovější verze WordPress</a>. Kontaktujte prosím správce serveru, aby aktualizoval vaši verzi PHP.','Advanced'=>'Pokročilé','Settings saved.'=>'Nastavení bylo uloženo.','Are you sure you want to remove this item?'=>'Opravdu chcete odstranit tuto položku?','Remove'=>'Odstranit','Add'=>'Přidat','Select...'=>'Vybrat...','[%s] Low TranslatePress AI Words'=>'[%s] Docházejí slova TranslatePress AI','upgrade your plan or get extra AI Words'=>'upgradujte svůj tarif nebo získejte další slova AI','upgrade your plan'=>'upgradujte svůj tarif','TranslatePress AI words are running low on your site.'=>'Na vašem webu docházejí slova TranslatePress AI.','Current status: %s words remaining'=>'Aktuální stav: %s zbývajících slov','Once the remaining AI words run out, automatic translation through TranslatePress AI will be paused.'=>'Jakmile dojdou zbývající slova AI, automatický překlad prostřednictvím TranslatePress AI bude pozastaven.','To continue translating your content, please %1$s over at %2$s'=>'Chcete-li pokračovat v překladu svého obsahu, proveďte prosím %1$s na stránce %2$s','Manage Notification: %s'=>'Spravovat oznámení: %s','There is a new version of %1$s available. %2$sView version %3$s details%4$s or %5$supdate now%6$s.'=>'Je dostupná nová verze %1$s. %2$sZobrazit podrobnosti verze %3$s%4$s nebo %5$saktualizovat nyní%6$s.','There is a new version of %1$s available. %2$sView version %3$s details%4$s.'=>'Je dostupná nová verze %1$s. %2$sZobrazit podrobnosti verze %3$s%4$s.','To enable updates, please %1$senter your license key%2$s. Need a license key? %3$sPurchase one now%4$s.'=>'Chcete-li povolit aktualizace, %1$szadejte prosím svůj licenční klíč%2$s. Potřebujete licenční klíč? %3$sKupte si jej nyní%4$s.','To enable updates, please go to the %1$slicense page%2$s and check that you have a valid license.'=>'Chcete-li povolit aktualizace, přejděte prosím na %1$sstránku licence%2$s a zkontrolujte, že máte platnou licenci.','To enable updates, your licence needs to be renewed. Please go to the %1$sTranslatePress Account%2$s page and login to renew.'=>'Chcete-li povolit aktualizace, je třeba obnovit vaši licenci. Přejděte prosím na stránku %1$sTranslatePress Account%2$s a přihlaste se k obnovení.','You do not have permission to install plugin updates'=>'Nemáte oprávnění k instalaci aktualizací pluginů','Error'=>'Chyba','Your TranslatePress license key is invalid or missing.'=>'Váš licenční klíč TranslatePress je neplatný nebo chybí.','Your license key expired on %s.'=>'Platnost vašeho licenčního klíče vypršela %s.','Your license key has been disabled.'=>'Váš licenční klíč byl deaktivován.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Váš licenční klíč je pro tuto URL deaktivován. Znovu jej aktivujte na <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Správa webů.','<p><strong>License key mismatch.</strong> The license you entered doesn’t match the TranslatePress version you have installed.</p><p>Please check that you’ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>Neshoda licenčního klíče.</strong> Zadaná licence neodpovídá verzi TranslatePress, kterou máte nainstalovanou.</p><p>Zkontrolujte prosím, že jste ze svého účtu TranslatePress nainstalovali správnou verzi pro vaši licenci.</p>','If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'Pokud máte nainstalovaný pouze bezplatný plugin, ale přidali jste si placenou licenci, nainstalujte si prosím placený plugin ze svého účtu TranslatePress.','Your license key has reached its activation limit.'=>'Váš licenční klíč dosáhl limitu aktivací.','Upgrade your plan to add more sites. %1$sUpgrade now%2$s'=>'Upgradujte svůj plán pro přidání dalších webů. %1$sUpgradovat nyní%2$s','This website is already activated under a free license. Each website can only use one free license.'=>'Tento web je již aktivován pod bezplatnou licencí. Každý web může používat pouze jednu bezplatnou licenci.','An error occurred, please try again.'=>'Došlo k chybě, zkuste to prosím znovu.','You have successfully activated your license'=>'Úspěšně jste aktivovali svou licenci','Others'=>'Ostatní','Restrict by Language'=>'Omezit podle jazyka','Exclude from Language'=>'Vyloučit z jazyka','Restrict element to language'=>'Omezit prvek na jazyk','Show this element only in one language.'=>'Zobrazit tento prvek pouze v jednom jazyce.','Enable translation'=>'Povolit překlad','Allow translation to the corresponding language only if the content is written in the default language.'=>'Povolit překlad do příslušného jazyka pouze v případě, že je obsah napsán ve výchozím jazyce.','Select language'=>'Vybrat jazyk','Choose in which language to show this element.'=>'Vyberte, v jakém jazyce se má tento prvek zobrazit.','Exclude element from language'=>'Vyloučit prvek z jazyka','Exclude this element from specific languages.'=>'Vyloučit tento prvek z konkrétních jazyků.','Select languages'=>'Vybrat jazyky','Choose from which languages to exclude this element.'=>'Vyberte, ze kterých jazyků se má tento prvek vyloučit.','This element will still be visible when you are translating your website through the Translation Editor.'=>'Tento prvek bude stále viditelný při překladu vašeho webu prostřednictvím překladového editoru.','The content of this element should be written in the default language.'=>'Obsah tohoto prvku by měl být napsán ve výchozím jazyce.','<strong>TranslatePress</strong> encountered SQL errors. <a href="%s" title="View TranslatePress SQL Errors">Check out the errors</a>.'=>'<strong>TranslatePress</strong> zaznamenal SQL chyby. <a href="%s" title="Zobrazit SQL chyby TranslatePress">Zobrazit chyby</a>.','Automatic translation has been disabled.'=>'Automatický překlad byl zakázán.','Dismiss this notice.'=>'Skrýt toto oznámení.','Logged errors'=>'Zaznamenané chyby','These are the most recent 5 errors logged by TranslatePress:'=>'Toto je 5 nejnovějších chyb zaznamenaných TranslatePress:','Yes'=>'Ano','Why are these errors occuring'=>'Proč dochází k těmto chybám','If TranslatePress detects something wrong when executing queries on your database, it may disable the Automatic Translation feature in order to avoid any extra charging by Google/DeepL. Automatic Translation needs to be manually turned on, after you solve the issues.'=>'Pokud TranslatePress při provádění dotazů ve vaší databázi zjistí nějaký problém, může zakázat funkci automatického překladu, aby se zabránilo dalšímu účtování od Google/DeepL. Po vyřešení problémů je nutné automatický překlad ručně znovu zapnout.','The SQL errors detected can occur for various reasons including missing tables, missing permissions for the SQL user to create tables or perform other operations, problems after site migration or changes to SQL server configuration.'=>'Zjištěné chyby SQL mohou nastat z různých důvodů, včetně chybějících tabulek, chybějících oprávnění uživatele SQL k vytváření tabulek nebo provádění jiných operací, problémů po migraci webu nebo změn v konfiguraci SQL serveru.','What you can do in this situation'=>'Co můžete v této situaci udělat','Plan A.'=>'Plán A.','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL settings. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Přejděte na Nastavení -> TranslatePress -> kartu Obecné a uložte nastavení. Tím se znovu vygenerují tabulky pomocí vašeho aktuálního nastavení SQL. Zkontrolujte, zda při procházení vašeho webu v přeloženém jazyce nedochází k dalším chybám. Podívejte se na časová razítka chyb, abyste se ujistili, že nevidíte staré chyby. Zobrazuje se pouze 5 nejnovějších chyb.','Plan B.'=>'Plán B.','If your problem isn\'t solved, try the following steps:'=>'Pokud váš problém není vyřešen, zkuste následující kroky:','Create a backup of your database'=>'Vytvořte zálohu své databáze','Create a copy of each translation table where you encounter errors. You can copy the table within the same database (trp_dictionary_en_us_es_es_COPY for example) -- perform this step only if you want to keep the current translations'=>'Vytvořte kopii každé překladové tabulky, u které se vyskytují chyby. Tabulku můžete zkopírovat ve stejné databázi (například trp_dictionary_en_us_es_es_COPY) -- tento krok proveďte pouze tehdy, pokud chcete zachovat aktuální překlady.','Remove the trouble tables by executing the DROP function on them'=>'Odstraňte problematické tabulky provedením funkce DROP na nich','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL server.'=>'Přejděte na Nastavení -> TranslatePress -> kartu Obecné a uložte nastavení. Tím se znovu vygenerují tabulky pomocí vašeho aktuálního SQL serveru.','Copy the relevant content from the duplicated tables (trp_dictionary_en_us_es_es_COPY for example) in the newly generated table (trp_dictionary_en_us_es_es) -- perform this step only if you want to keep the current translations'=>'Zkopírujte relevantní obsah z duplikovaných tabulek (například trp_dictionary_en_us_es_es_COPY) do nově vygenerované tabulky (trp_dictionary_en_us_es_es) -- tento krok proveďte pouze tehdy, pokud chcete zachovat aktuální překlady.','Test it to see if everything is working. If something went wrong, you can restore the backup that you\'ve made at the first step. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Otestujte, zda vše funguje. Pokud se něco pokazilo, můžete obnovit zálohu, kterou jste vytvořili v prvním kroku. Zkontrolujte, zda při procházení vašeho webu v přeloženém jazyce nedochází k dalším chybám. Podívejte se na časová razítka chyb, abyste se ujistili, že nevidíte staré chyby. Zobrazuje se pouze 5 nejnovějších chyb.','Plan C.'=>'Plán C.','If your problem still isn\'t solved, try asking your hosting about your errors. The most common issue is missing permissions for the SQL user, such as the Create Tables permission.'=>'Pokud váš problém stále není vyřešen, zkuste se zeptat svého poskytovatele hostingu na tyto chyby. Nejčastějším problémem jsou chybějící oprávnění uživatele SQL, například oprávnění k vytváření tabulek.','Could not install. Try again from <a href="%s" >Plugins Dashboard.</a>'=>'Nepodařilo se nainstalovat. Zkuste to znovu na <a href="%s" >stránce pluginů.</a>','Active'=>'Aktivní','Permission denied.'=>'Oprávnění odepřeno.','Invalid nonce.'=>'Neplatný nonce.','Settings scope unknown.'=>'Neznámý rozsah nastavení.','Legacy disabled.'=>'Zastaralé zakázáno.','Language Switcher'=>'Přepínač jazyka','Change language to %s'=>'Změnit jazyk na %s','Automatic Translation'=>'Automatický překlad','DeepL'=>'DeepL','Unsupported languages'=>'Nepodporované jazyky','The selected automatic translation engine does not provide support for these languages.<br>You can still manually translate pages in these languages using the Translation Editor.'=>'Vybraný automatický překladový stroj nepodporuje tyto jazyky.<br>Stránky v těchto jazycích můžete stále překládat ručně pomocí editoru překladů.','API key validation failed.'=>'Ověření API klíče selhalo.','API key verification was successful.'=>'Ověření API klíče bylo úspěšné.','Please enter your Google Translate key.'=>'Zadejte svůj klíč Google Translate.','Please enter your DeepL API key.'=>'Zadejte svůj DeepL API klíč.','Not TranslatePress onboarding page.'=>'Toto není úvodní stránka TranslatePress.','Step %s does not exist'=>'Krok %s neexistuje','Welcome'=>'Vítejte','Add Languages'=>'Přidat jazyky','Enable Addons'=>'Povolit doplňky','Finalize'=>'Dokončit','Exit Setup'=>'Ukončit nastavení','Upgrade'=>'Upgradovat','Nothing here'=>'Zde nic není','Your <strong>TranslatePress</strong> license is missing or invalid. <br/>Please %1$sregister your copy%2$s to enable automatic website translation via TranslatePress AI, premium addons, automatic updates and support. Need a license key? %3$sPurchase one now%4$s'=>'Vaše licence <strong>TranslatePress</strong> chybí nebo je neplatná. <br/>Prosím, %1$szaregistrujte svou kopii%2$s, abyste mohli používat automatický překlad webu pomocí TranslatePress AI, prémiová rozšíření, automatické aktualizace a podporu. Potřebujete licenční klíč? %3$sZakupte si jej nyní%4$s','Your <strong>TranslatePress</strong> license will expire on %1$s. Please %2$sRenew Your Licence%3$s to continue receiving access to automatic translations via TP AI, premium addons, product downloads and automatic updates. %4$sRenew Now%5$s'=>'Vaše licence <strong>TranslatePress</strong> vyprší dne %1$s. Prosím, %2$sObnovte svou licenci%3$s pro zachování přístupu k automatickým překladům pomocí TP AI, prémiovým rozšířením, stahování produktů a automatickým aktualizacím. %4$sObnovit nyní%5$s','Error: '=>'Chyba: ','Something went wrong, please try again.'=>'Něco se pokazilo, zkuste to prosím znovu.','Your <strong>TranslatePress</strong> license has expired. <br/>Please %1$sRenew Your Licence%2$s to continue receiving access to automatic translations via TranslatePress AI, premium addons, product downloads, and automatic updates. %3$sRenew now %4$s'=>'Vaše licence <strong>TranslatePress</strong> vypršela. <br/>Prosím, %1$sObnovte svou licenci%2$s pro zachování přístupu k automatickým překladům pomocí TranslatePress AI, prémiovým rozšířením, stahování produktů a automatickým aktualizacím. %3$sObnovit nyní %4$s','License key mismatch. The license you entered doesn’t match the <strong>%1$s</strong> version you have installed. <br/>Please check that you’ve installed the correct version for your license from your %2$sTranslatePress account%3$s.'=>'Neshoda licenčního klíče. Zadaná licence neodpovídá verzi <strong>%1$s</strong>, kterou máte nainstalovanou. <br/>Zkontrolujte prosím, že máte z vašeho %2$sTranslatePress Account%3$s nainstalovanou správnou verzi pro vaši licenci.','<br/>If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'<br/>Pokud máte nainstalovaný pouze bezplatný plugin, ale zadali jste placenou licenci, nainstalujte si prosím placený plugin z vašeho TranslatePress Account.','You have reached the activation limit for your <strong>%1$s</strong> license. <br/>Manage your active sites from %2$s your account %3$s.'=>'Dosáhli jste limitu aktivací pro vaši licenci <strong>%1$s</strong>. <br/>Spravujte své aktivní weby ve %2$s vašem účtu %3$s.','Your license is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Vaše licence je pro tuto URL deaktivována. Znovu ji aktivujte na stránce <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Správa webů.','%1$s automatic translation requires an active license. Please %2$srenew%3$s your license or purchase a new one %4$shere%5$s.'=>'Automatický překlad %1$s vyžaduje aktivní licenci. Prosím, %2$sobnovte%3$s svou licenci nebo si zakupte novou %4$szde%5$s.','Please %1$senter%2$s your license key to enable %3$s automatic translation.'=>'Prosím, %1$szadejte%2$s svůj licenční klíč, abyste povolili automatický překlad %3$s.','You have less than 5,000 TranslatePress AI words remaining. To continue automatically translating your website, please %spurchase additional AI words at a discount from your account%s.'=>'Zbývá vám méně než 5 000 slov TranslatePress AI. Chcete-li pokračovat v automatickém překladu svého webu, %szakupte si dodatečná AI slova se slevou na svém účtu%s.',' Error: '=>' Chyba: ','This website is already activated under a free license. Each website can only use one free license. Please upgrade to a premium plan for more TranslatePress AI words from %1$s your account %2$s.'=>'Tento web je již aktivován pod bezplatnou licencí. Každý web může používat pouze jednu bezplatnou licenci. Chcete-li získat více slov TranslatePress AI, upgradujte na prémiový plán z %1$s vašeho účtu %2$s.','You do not have a valid license for <strong>TranslatePress</strong>. %1$sGet one for free%2$s to get access to TranslatePress AI.'=>'Nemáte platnou licenci pro <strong>TranslatePress</strong>. %1$sZískejte ji zdarma%2$s a získejte přístup k TranslatePress AI.','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. Upgrade to <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business or Developer</a> to access it + more premium perks!'=>'<strong>NOVÉ:</strong> Je tu doplněk <strong>Different Domain per Language</strong>! Podpořte své globální SEO a vytvořte místní zážitek s doménami specifickými pro jednotlivé země, jako jsou .de nebo .fr. Upgradujte na <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business nebo Developer</a> a získejte k němu přístup i další prémiové výhody!','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Learn more</a>.'=>'<strong>NOVÉ:</strong> Je tu doplněk <strong>Different Domain per Language</strong>! Podpořte své globální SEO a vytvořte místní zážitek s doménami specifickými pro jednotlivé země, jako jsou .de nebo .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Zjistit více</a>.','The daily quota for machine translation characters exceeded. Please check the <strong>TranslatePress -> <a href="%s">Automatic Translation</a></strong> page for more information.'=>'Byla překročena denní kvóta znaků pro strojový překlad. Další informace naleznete na stránce <strong>TranslatePress -> <a href="%s">Automatický překlad</a></strong>.','Marketing optin'=>'Marketingový souhlas','Opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Udělte souhlas s odběrem oznámení o bezpečnostních a funkčních aktualizacích a s diagnostickým sledováním bez citlivých údajů.','TranslatePress Preferred User Language'=>'Preferovaný jazyk uživatele TranslatePress','Preferred language to navigate the site'=>'Preferovaný jazyk pro procházení webu','The language is automatically set based by the last visited language by the user.'=>'Jazyk se automaticky nastavuje podle posledního jazyka, který uživatel navštívil.','Always use this language'=>'Vždy používat tento jazyk','By checking this setting the preferred language will remain the one selected above, without the possibility of being changed in the frontend.<br>This language will be used in different operations such as sending email to the user.'=>'Zaškrtnutím tohoto nastavení zůstane preferovaný jazyk nastaven na výše vybraný jazyk bez možnosti jeho změny na frontendu.<br>Tento jazyk bude použit při různých operacích, například při odesílání e-mailu uživateli.','Hello! Seems like you\'ve been using <strong>TranslatePress</strong> for a while now to translate your website. That\'s awesome! '=>'Dobrý den! Zdá se, že již nějakou dobu používáte <strong>TranslatePress</strong> k překladu svého webu. To je skvělé! ','If you can spare a few moments to rate it on WordPress.org it would help us a lot (and boost my motivation).'=>'Pokud si najdete chvilku na jeho ohodnocení na WordPress.org, velmi nám to pomůže (a zvýší mou motivaci).','~ Razvan, developer of TranslatePress'=>'~ Razvan, vývojář TranslatePress','Rate TranslatePress on WordPress.org plugin page'=>'Ohodnotit TranslatePress na stránce pluginu WordPress.org','Ok, I will gladly help!'=>'Dobře, rád pomohu!','No, thanks.'=>'Ne, děkuji.','Full Language Names'=>'Plné názvy jazyků','Short Language Names'=>'Zkrácené názvy jazyků','Flags with Full Language Names'=>'Vlajky s plnými názvy jazyků','Flags with Short Language Names'=>'Vlajky se zkrácenými názvy jazyků','Only Flags'=>'Pouze vlajky','Full Language Names No HTML'=>'Plné názvy jazyků bez HTML','Bottom Right'=>'Vpravo dole','Bottom Left'=>'Vlevo dole','Top Right'=>'Vpravo nahoře','Top Left'=>'Vlevo nahoře','Dark'=>'Tmavý','Light'=>'Světlý','Deactivate'=>'Deaktivovat','Activate'=>'Aktivovat','Invalid language code. Please try again.'=>'Neplatný kód jazyka. Zkuste to prosím znovu.','Language codes can contain only A-Z a-z 0-9 - _ characters. Check your language codes in TranslatePress General Settings.'=>'Kódy jazyků mohou obsahovat pouze znaky A-Z a-z 0-9 - _. Zkontrolujte své kódy jazyků v obecném nastavení TranslatePress.','Error! Duplicate URL slug values.'=>'Chyba! Duplicitní hodnoty URL slug.','You cannot select two languages that have the same <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">iso code</a> but different formalities because doing so will lead to 